PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS users(id INTEGER PRIMARY KEY AUTOINCREMENT,public_id TEXT NOT NULL UNIQUE,pair_id TEXT NOT NULL UNIQUE,pair_status TEXT NOT NULL DEFAULT 'ACTIVE',name TEXT NOT NULL,email TEXT NOT NULL UNIQUE COLLATE NOCASE,password_hash TEXT NOT NULL,password_salt TEXT NOT NULL,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS wallets(id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER NOT NULL UNIQUE,balance TEXT NOT NULL DEFAULT '0',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS genesis(id INTEGER PRIMARY KEY CHECK(id=1),tx_id TEXT NOT NULL UNIQUE,owner_user_id INTEGER NOT NULL,total_supply TEXT NOT NULL,pair_proof TEXT NOT NULL,created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS transactions(id INTEGER PRIMARY KEY AUTOINCREMENT,tx_id TEXT NOT NULL UNIQUE,tx_type TEXT NOT NULL CHECK(tx_type IN('GENESIS','TRANSFER')),from_user_id INTEGER,to_user_id INTEGER NOT NULL,amount TEXT NOT NULL,memo TEXT,pair_proof TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'COMPLETED',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS ledger(id INTEGER PRIMARY KEY AUTOINCREMENT,tx_id TEXT NOT NULL,user_id INTEGER NOT NULL,counterparty_user_id INTEGER,entry_type TEXT NOT NULL CHECK(entry_type IN('CREDIT','DEBIT')),amount TEXT NOT NULL,balance_after TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'COMPLETED',created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);
CREATE INDEX IF NOT EXISTS idx_ledger_user ON ledger(user_id,created_at DESC);
